import React, { useState } from "react";
import { Link } from "react-router-dom";
import { motion } from "framer-motion";
import "../styles/PropertyCard.css";

const PropertyCard = ({ property }) => {
    const [isFlipped, setIsFlipped] = useState(false);

    if (!property) return null;

    const getDefaultImage = (type) => {
        switch (type) {
            case "Apartment":
                return "https://images.unsplash.com/photo-1545324418-cc1a3fa10c00?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80";
            case "Villa":
                return "https://images.unsplash.com/photo-1580587771525-78b9bed3b978?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80";
            case "Plot":
                return "https://images.unsplash.com/photo-1500382017468-9049fed747ef?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80";
            case "House":
            default:
                return "https://images.unsplash.com/photo-1570129477492-45c003edd2be?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80";
        }
    };

    const imageUrl = property.images && property.images.length > 0
        ? property.images[0]
        : getDefaultImage(property.propertyType);

    const containerVariants = {
        hidden: { opacity: 0, y: 20 },
        visible: { 
            opacity: 1, 
            y: 0,
            transition: { duration: 0.5 }
        }
    };

    const hoverVariants = {
        initial: { scale: 1, rotateZ: 0 },
        hover: { 
            scale: 1.05, 
            rotateZ: 2,
            boxShadow: "0 20px 40px rgba(0, 0, 0, 0.3)",
            transition: { duration: 0.3 }
        }
    };

    return (
        <motion.div
            className="property-card"
            variants={containerVariants}
            initial="hidden"
            animate="visible"
            whileHover="hover"
            variants={hoverVariants}
            onClick={() => setIsFlipped(!isFlipped)}
            onMouseEnter={() => setIsFlipped(false)}
        >
            <motion.div
                className="property-card-inner"
                animate={{ rotateY: isFlipped ? 180 : 0 }}
                transition={{ duration: 0.6 }}
                style={{ transformStyle: "preserve-3d" }}
            >
                {/* Front side */}
                <motion.div
                    className="property-card-front"
                    style={{ backfaceVisibility: "hidden" }}
                >
                    <div className="property-image">
                        <motion.img 
                            src={imageUrl} 
                            alt={property.title}
                            whileHover={{ scale: 1.1 }}
                            transition={{ duration: 0.3 }}
                        />
                        <motion.div 
                            className="property-badge"
                            whileHover={{ scale: 1.1 }}
                        >
                            {property.propertyType}
                        </motion.div>
                        <motion.div 
                            className="property-status-badge"
                            initial={{ x: -100 }}
                            animate={{ x: 0 }}
                        >
                            {property.status}
                        </motion.div>
                    </div>
                    <div className="property-info">
                        <motion.h3
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            transition={{ delay: 0.2 }}
                        >
                            {property.title}
                        </motion.h3>
                        <motion.p 
                            className="location"
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            transition={{ delay: 0.3 }}
                        >
                            📍 {property.location?.city}, {property.location?.state}
                        </motion.p>
                        <motion.div 
                            className="price-row"
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.4 }}
                        >
                            <span className="price">₹{property.price?.toLocaleString()}</span>
                            <Link to={`/properties/${property._id}`} className="view-btn">
                                View Details
                            </Link>
                        </motion.div>
                    </div>
                </motion.div>

                {/* Back side */}
                <motion.div
                    className="property-card-back"
                    style={{ 
                        backfaceVisibility: "hidden",
                        rotateY: 180
                    }}
                >
                    <div className="property-details">
                        <h4>Property Details</h4>
                        <div className="detail-item">
                            <span className="label">Type:</span>
                            <span className="value">{property.propertyType}</span>
                        </div>
                        <div className="detail-item">
                            <span className="label">Status:</span>
                            <span className="value">{property.status}</span>
                        </div>
                        {property.bedrooms && (
                            <div className="detail-item">
                                <span className="label">Bedrooms:</span>
                                <span className="value">{property.bedrooms}</span>
                            </div>
                        )}
                        {property.bathrooms && (
                            <div className="detail-item">
                                <span className="label">Bathrooms:</span>
                                <span className="value">{property.bathrooms}</span>
                            </div>
                        )}
                        {property.area && (
                            <div className="detail-item">
                                <span className="label">Area:</span>
                                <span className="value">{property.area} sqft</span>
                            </div>
                        )}
                        <Link to={`/properties/${property._id}`} className="view-link">
                            View Full Details →
                        </Link>
                    </div>
                </motion.div>
            </motion.div>
        </motion.div>
    );
};

export default PropertyCard;
